import { Box, chakra, Flex } from '@chakra-ui/react';
import { usePinnedContainerRef } from '@ui/utils';
import { ReactNode, Suspense, useLayoutEffect, useMemo, useRef } from 'react';
import { Loading } from '../Loading';
import { Nav } from './components/Nav';
import { NavAccountPicker } from './components/Nav/components/NavAccountPicker/NavAccountPicker';
import { safeMarginsBelowTopNav } from './components/Nav/constants';
import useNavRoutes from './components/Nav/hooks/useNavRoutes';

interface IProps {
  children: ReactNode;
  showAccountPicker?: boolean;
}

export const PageLayout = ({ children, showAccountPicker = true }: IProps): JSX.Element => {
  const routes = useNavRoutes();
  const localRef = useRef<HTMLDivElement>(null);
  const { ref, setRef } = usePinnedContainerRef();
  const variant = useMemo(
    () =>
      window.location?.host?.startsWith('qa')
        ? 'navQa'
        : window.location?.host?.indexOf('sandbox') > -1
          ? 'navSandbox'
          : 'nav',
    []
  );

  useLayoutEffect(() => {
    if (localRef.current && !ref?.current) {
      setRef(localRef);
    }
  }, [ref, setRef]);

  return (
    <>
      <Flex direction="column" flex="1" height="100%" overflow="hidden">
        <Nav
          accountPicker={
            showAccountPicker ? (
              <Box ml={5} mr={8}>
                <NavAccountPicker variant={variant} />
              </Box>
            ) : null
          }
          indexPath="/accounts"
          routes={routes}
          variant={variant}
        />
        <Suspense fallback={<Loading />}>
          <Flex
            bgColor="neutral.0"
            flexDirection="column"
            flexGrow={1}
            {...safeMarginsBelowTopNav}
            overflow="hidden"
          >
            {children}
          </Flex>
        </Suspense>
      </Flex>
      <chakra.div flexShrink={0} ref={localRef} />
    </>
  );
};

