import {
  Box,
  Button,
  Drawer,
  DrawerContent,
  Flex,
  useBreakpointValue,
  useDisclosure,
} from '@chakra-ui/react';
import { Children, ReactNode, useLayoutEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useLocation } from 'react-router-dom';
import { ToggleChevron } from '../ToggleChevron';
import { SidebarContainer } from '../templates/SidebarContainer';
import { Label } from '../typography/Text';
import { settingsNavHeight, topNavHeight } from './components/Nav/constants';

export const SettingsNavLayout = ({ children }: { children: ReactNode }) => {
  const [sidebarChild, ...otherChildren] = Children.toArray(children);
  const isFullNav = useBreakpointValue({ base: false, md: true }) ?? false;
  const { isOpen, onClose, onToggle } = useDisclosure();

  // Listen for route changes to detect whether a menu selection was made
  const location = useLocation();
  // biome-ignore lint/correctness/useExhaustiveDependencies: intentional extra dependencies
  useLayoutEffect(() => {
    return () => {
      // Throwing onClose here seems to have the smoothest looking experience
      onClose();
    };
  }, [location, isFullNav, onClose]);
  const { t } = useTranslation('settings');

  if (isFullNav) {
    return (
      <Flex h={`calc(100vh - ${topNavHeight})`}>
        <Flex
          backgroundColor="neutral.100"
          flexDir="column"
          flexShrink={0}
          height="100%"
          overflowX="hidden"
          overflowY="auto"
          paddingBottom={14}
        >
          <SidebarContainer lineHeight="28px" title={t('title')} width="212px">
            {sidebarChild}
          </SidebarContainer>
        </Flex>
        <Flex direction="column" flex="1" overflow="hidden">
          {otherChildren}
        </Flex>
      </Flex>
    );
  }

  return (
    <Flex direction="column" h="full" w="full">
      <Button isActive={isOpen} onClick={onToggle} size="lg" variant="settingsNav" zIndex="sticky">
        <Flex alignItems="center" flexDirection="row" justifyContent="space-between" w="full">
          <Label variant="bold">{t('title')}</Label>
          <ToggleChevron color="neutral.600" isOpen={isOpen} />
        </Flex>
      </Button>
      <Drawer isOpen={isOpen} onClose={onClose} placement="top" size="full">
        <Box
          // Sets the zindex lower so that the drawer doesn't cover the top nav or button
          sx={{
            '.chakra-modal__content-container': {
              zIndex: 'dropdown',
            },
          }}
        >
          <DrawerContent
            h={`calc(100vh - ${topNavHeight} - ${settingsNavHeight})`}
            mt={`calc(${topNavHeight} + ${settingsNavHeight})`}
          >
            <Flex direction="column" gap={4} overflow="auto" py={2}>
              {sidebarChild}
            </Flex>
          </DrawerContent>
        </Box>
      </Drawer>
      <Flex
        direction="column"
        flexGrow={1}
        overflowX="hidden"
        overflowY="scroll"
        position="relative"
      >
        {otherChildren}
      </Flex>
    </Flex>
  );
};

